mapper.select:
SELECT ci.v_career_id , ci.v_career_nm , to_char(ci.d_start_dtm, 'YYYY-MM-DD') as d_start_dtm , to_char(ci.d_end_dtm, 'YYYY-MM-DD') as d_end_dtm , (EXTRACT(year FROM AGE(d_end_dtm, d_start_dtm)) * 12 + EXTRACT(month FROM AGE(d_end_dtm, d_start_dtm))) AS total_months FROM career_info ci WHERE ci.v_flag_del = 'N'
AND ci.v_career_id = #{vCareerId}
ORDER BY ci.d_start_dtm

mapper.update:
UPDATE career_info
   SET v_career_nm = #{vCareerNm}
     , d_start_dtm = #{dStartDtm}::timestamp
     , d_end_dtm = #{dEndDtm}::timestamp
 WHERE v_career_id = #{vCareerId}
